import{_ as a,o as t,c as r,ae as o}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"SEO + AIO Implementation","description":"","frontmatter":{"title":"SEO + AIO Implementation","slug":"seo-aio-implementation"},"headers":[],"relativePath":"developer-hub/seo-aio-implementation.md","filePath":"developer-hub/seo-aio-implementation.md"}'),i={name:"developer-hub/seo-aio-implementation.md"};function n(s,e,l,c,h,d){return t(),r("div",null,[...e[0]||(e[0]=[o('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>SEO + AIO App Attribution tracks and attributes organic traffic from search engines and AI chat agents. When users arrive from Google, Bing, ChatGPT, Claude, Gemini, Copilot, or Perplexity, Branch identifies the source and attributes the session correctly.</p><p>This feature shows which content drove each visit and organizes traffic in dedicated channels (&quot;organic search&quot; for search engines and &quot;organic chat agent&quot; for AI chat agents) giving you a complete view of how users discover your app.</p><h2 id="how-it-works" tabindex="-1">How it works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How it works&quot;">​</a></h2><h3 id="seo" tabindex="-1">SEO <a class="header-anchor" href="#seo" aria-label="Permalink to &quot;SEO&quot;">​</a></h3><ol><li><p><strong>User clicks a result from a search engine</strong><br> The user clicks a link from a supported search engine (Google, Bing, Yahoo, Naver, Daum, DuckDuckGo, etc.) that points to your top-level domain.</p></li><li><p><strong>Links are indexed by the search engine</strong><br> Your site content has already been crawled and indexed by search engines, so those URLs appear in search results.</p></li><li><p><strong>Branch collects specific signals on app open</strong><br> When your app opens from that domain using Universal Links / App Links, the Branch SDK receives the necessary referrer and device context.</p></li><li><p><strong>Branch simulates a click</strong><br> Branch creates a synthetic click in the background using those signals.</p></li><li><p><strong>Branch attributes the user to Organic Search</strong><br> The resulting install, open, or event is attributed with:</p><ul><li><code>~feature</code> = &quot;organic search&quot;</li><li><code>~channel</code> = search engine name</li><li><code>~organic_search_url</code> = originating URL</li></ul></li></ol><h3 id="aio" tabindex="-1">AIO <a class="header-anchor" href="#aio" aria-label="Permalink to &quot;AIO&quot;">​</a></h3><ol><li><p><strong>User clicks a link from an AI chat agent</strong><br> The user clicks a link from a supported AI chat agent (ChatGPT, Claude, Gemini, Copilot, Perplexity) that points to your top-level domain.</p></li><li><p><strong>Link opens in browser or webview</strong><br> The AI agent opens your link, typically with UTM parameters (like <code>utm_source=chatgpt</code>) or an identifiable referrer.</p></li><li><p><strong>Branch collects specific signals on app open</strong><br> When your app opens from that domain using Universal Links / App Links, the Branch SDK receives the URL, UTM parameters, and referrer information.</p></li><li><p><strong>Branch simulates a click</strong><br> Branch creates a synthetic click in the background using those signals.</p></li><li><p><strong>Branch attributes the user to &quot;organic chat agent&quot;</strong><br> The resulting install, open, or event is attributed with:</p><ul><li><code>~feature</code> = &quot;organic chat agent&quot;</li><li><code>~channel</code> = AI chat agent name</li><li><code>~organic_search_url</code> = originating URL</li></ul></li></ol><p>Branch identifies each AI chat agent by checking UTM parameters (like <code>utm_source=chatgpt</code>) and referrer domains (like <code>chatgpt.com</code>, <code>gemini.google.com</code>, <code>perplexity.ai</code>).</p><h2 id="before-you-begin" tabindex="-1">Before you begin <a class="header-anchor" href="#before-you-begin" aria-label="Permalink to &quot;Before you begin&quot;">​</a></h2><p>To enable SEO + AIO App Attribution, you must complete the following tasks:</p><ol><li>Create a Branch account.</li><li>Enable SEO App Attribution for your Branch account. Contact your Branch account manager or visit <a href="https://branch.io/pricing." target="_blank" rel="noreferrer">https://branch.io/pricing.</a></li></ol><div class="info custom-block"><p class="custom-block-title">Note</p><p>AIO uses the same provisioning switch as SEO. Once SEO App Attribution is enabled for your app, AIO attribution will automatically be available.</p></div><ol start="3"><li>Implement the latest version Branch SDK into your mobile app (<a href="./ios-sdk-overview.html">iOS</a>, <a href="./android-sdk-overview.html">Android</a>).</li></ol><h2 id="set-up-seo-aio-app-attribution" tabindex="-1">Set up SEO + AIO App Attribution <a class="header-anchor" href="#set-up-seo-aio-app-attribution" aria-label="Permalink to &quot;Set up SEO + AIO App Attribution&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Developer required</p><p>iOS and Android developers are required to enable SEO + AIO App Attribution.</p></div><h3 id="_1-verify-sdk-versions" tabindex="-1">1. Verify SDK versions <a class="header-anchor" href="#_1-verify-sdk-versions" aria-label="Permalink to &quot;1. Verify SDK versions&quot;">​</a></h3><ul><li>Confirm that your Branch iOS SDK version is <a href="./ios-version-history.html">v1.39.4+</a></li><li>Confirm that your Branch Android SDK version is <a href="./android-version-history.html">v5.0.12+</a></li></ul><h3 id="_2-set-up-universal-links-and-app-links-on-your-top-level-domain" tabindex="-1">2. Set up Universal Links and App Links on your top-level domain <a class="header-anchor" href="#_2-set-up-universal-links-and-app-links-on-your-top-level-domain" aria-label="Permalink to &quot;2. Set up Universal Links and App Links on your top-level domain&quot;">​</a></h3><p>iOS <a href="./ios-universal-links.html">Universal Links</a> and Android <a href="./android-app-links.html">App Links</a> are required on your top-level domain for organic search and AI chat agent traffic to deep link users to in-app content.</p><div class="info custom-block"><p class="custom-block-title">Note</p><p>You must enable iOS Universal Links or Android App Links on your top-level domain (Branch recommends both). Attribution will work only for platforms where deep linking is enabled. For example, if you enable Universal Links but not App Links, you&#39;ll only see iOS data.</p><p>When configuring Universal Links and App Links, specify which paths should open your app. Some URLs (password reset, privacy policy, etc.) should remain web-only and not trigger the app.</p></div><h3 id="_3-enter-seo-domains" tabindex="-1">3. Enter SEO domains <a class="header-anchor" href="#_3-enter-seo-domains" aria-label="Permalink to &quot;3. Enter SEO domains&quot;">​</a></h3><p>Select <strong>SEO</strong> under the <strong>Analysis</strong> section in Branch. On the <strong>SEO</strong> <strong>Configuration</strong> page, enter your domains. List each of the domains you want to enable SEO + AIO Attribution for.</p><div class="tip custom-block"><p class="custom-block-title">Tip</p><p>If you&#39;re on the new Branch experience, go to <strong>Configuration</strong> &gt; <strong>Attribution</strong> to enter your domains.</p></div><p>Wildcard characters are not supported, so you must specify the exact domain, like &quot;<a href="https://www.branch.io/" target="_blank" rel="noreferrer">www.branch.io</a>&quot;.</p><p>Include the URL scheme and host (for example, <code>https://www.branch.io</code>).</p><p><strong>These domains are used for both:</strong></p><ul><li>SEO App Attribution (organic search traffic)</li><li>AIO App Attribution (traffic from AI chat agents that surface URLs under these domains)</li></ul><h2 id="view-analytics" tabindex="-1">View analytics <a class="header-anchor" href="#view-analytics" aria-label="Permalink to &quot;View analytics&quot;">​</a></h2><p>Once complete, you can view your SEO + AIO App Attribution analytics in multiple places:</p><h3 id="branch-analysis-dashboards" tabindex="-1">Branch Analysis dashboards <a class="header-anchor" href="#branch-analysis-dashboards" aria-label="Permalink to &quot;Branch Analysis dashboards&quot;">​</a></h3><p>Navigate to <a href="./analysis-dashboards.html">Analysis</a> in Branch. Use the <a href="https://help.branch.io/docs/analysis-dashboards#dashboards" target="_blank" rel="noreferrer">Classic Suite - SEO Analytics</a> default dashboard to view both SEO and AIO analytics.</p><p>Use filters to:</p><ul><li>Break down traffic by channel (search engines and AI chat agents)</li><li>Analyze installs, opens, purchases, and other events from both SEO and AIO</li></ul><h3 id="legacy-reporting-experience" tabindex="-1">Legacy reporting experience <a class="header-anchor" href="#legacy-reporting-experience" aria-label="Permalink to &quot;Legacy reporting experience&quot;">​</a></h3><p>Navigate to <a href="https://dashboard.branch.io/seo/analytics" target="_blank" rel="noreferrer">SEO Analytics</a> in Branch. Here you can measure <strong>Trends</strong> and <strong>Performance</strong> through charts and tables.</p><p><em>[Image: SEO Chart]</em>.png)</p><p><em>[Image: SEO Table]</em>.png)</p><div class="info custom-block"><p class="custom-block-title">Note</p><p>SEO + AIO App Attribution has the same reporting capabilities as Branch&#39;s Ads product. For a detailed overview of ad analytics and how to customize them, view our <a href="./paid-ads-analytics.html">guide</a>.</p></div><h3 id="access-the-originating-url" tabindex="-1">Access the originating URL <a class="header-anchor" href="#access-the-originating-url" aria-label="Permalink to &quot;Access the originating URL&quot;">​</a></h3><p>You can access the originating URL through Branch&#39;s Dashboard Reports or Exports (through the <a href="./dashboard-custom-exports.html">Dashboard Custom Exports</a> or through the <a href="./buildexportrequest.html">Custom Exports API</a>).</p><ul><li>For Dashboard Reports, add the <code>Organic Search URL</code> column to the events table.</li><li>For Dashboard Custom Exports, include the <code>Organic Search URL</code> column when configuring your export.</li><li>For Custom Exports API, export the <code>last_attributed_touch_data_tilde_organic_search_url</code> field.</li></ul><p>For AI chat agent sessions, this field corresponds to the URL that the AI agent surfaced and that the user clicked, allowing you to see which piece of content the AI agent used to drive app engagement.</p><h2 id="analytic-tags" tabindex="-1">Analytic tags <a class="header-anchor" href="#analytic-tags" aria-label="Permalink to &quot;Analytic tags&quot;">​</a></h2><p>Branch surfaces SEO and AIO traffic in Branch and the <a href="https://help.branch.io/apidocs#data-apis" target="_blank" rel="noreferrer">Data APIs</a> using the following analytic tags.</p><h3 id="feature" tabindex="-1">~feature <a class="header-anchor" href="#feature" aria-label="Permalink to &quot;~feature&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Tag</th><th>Value</th><th>Example</th><th>Data API field</th></tr></thead><tbody><tr><td><code>~feature</code></td><td>organic search</td><td>organic search</td><td><code>last_attributed_touch_data_tilde_feature</code></td></tr><tr><td><code>~feature</code></td><td>organic chat agent</td><td>organic chat agent</td><td><code>last_attributed_touch_data_tilde_feature</code></td></tr></tbody></table><h3 id="channel" tabindex="-1">~channel <a class="header-anchor" href="#channel" aria-label="Permalink to &quot;~channel&quot;">​</a></h3><p>For SEO App Attribution, <code>~channel</code> is the search engine name:</p><ul><li>Google</li><li>Bing</li><li>Yahoo</li><li>Naver</li><li>Ask</li><li>DuckDuckGo</li><li>Yandex</li><li>Daum</li></ul><p>For AIO App Attribution, <code>~channel</code> is the AI chat agent name:</p><ul><li>ChatGPT</li><li>Claude</li><li>Gemini</li><li>Copilot</li><li>Perplexity</li></ul><table tabindex="0"><thead><tr><th>Tag</th><th>Value type</th><th>Example</th><th>Data API field</th></tr></thead><tbody><tr><td><code>~channel</code></td><td>Search engine name</td><td>Google</td><td><code>last_attributed_touch_data_tilde_channel</code></td></tr><tr><td><code>~channel</code></td><td>AI chat agent name</td><td>ChatGPT</td><td><code>last_attributed_touch_data_tilde_channel</code></td></tr></tbody></table><h3 id="organic-search-url" tabindex="-1">~organic_search_url <a class="header-anchor" href="#organic-search-url" aria-label="Permalink to &quot;~organic\\_search\\_url&quot;">​</a></h3><p>This tag provides the originating URL that led to the app session, whether surfaced via search engine or AI chat agent.</p><table tabindex="0"><thead><tr><th>Tag</th><th>Value</th><th>Example</th><th>Data API field</th></tr></thead><tbody><tr><td><code>~organic_search_url</code></td><td>Originating URL</td><td><a href="https://example.com/category/section" target="_blank" rel="noreferrer">https://example.com/category/section</a></td><td><code>last_attributed_touch_data_tilde_organic_search_url</code></td></tr></tbody></table><p>Use this value to identify the exact piece of content (page, article, product detail, etc.) that drove the app conversion.</p><h2 id="testing-and-troubleshooting" tabindex="-1">Testing and troubleshooting <a class="header-anchor" href="#testing-and-troubleshooting" aria-label="Permalink to &quot;Testing and troubleshooting&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">Note</p><p>If you don&#39;t see AIO data in Branch, you may need to clear your browser cache. Bookmarks and saved queries from before AIO was released are cached and may not load the new data. Try clearing your browser&#39;s cache to resolve this issue.</p><p>You can also try <a href="https://help.branch.io/docs/branch-summary-page#resetting" target="_blank" rel="noreferrer">resetting the page state</a>.</p></div><h3 id="check-ios-universal-links-and-android-app-links" tabindex="-1">Check iOS Universal Links and Android App Links <a class="header-anchor" href="#check-ios-universal-links-and-android-app-links" aria-label="Permalink to &quot;Check iOS Universal Links and Android App Links&quot;">​</a></h3><p>If you have completed all the setup steps above and are still running into issues, verify that iOS Universal Links and Android App Links are working properly.</p><ol><li><p>Find a URL that would appear in search results. For example, <a href="https://www.skyskanner.com/" target="_blank" rel="noreferrer">https://www.skyskanner.com/</a>.</p></li><li><p>Copy and paste that URL into a Universal Links or App Links compatible editor.</p></li><li><p>Confirm that your app is installed.</p></li><li><p>Select the link from the compatible editor.</p></li><li><p>Does your app open?</p><ul><li><strong>Yes</strong>: Continue to the next step.</li><li><strong>No</strong>: There&#39;s an issue with your Universal Links or App Links setup. Refer to <a href="./ios-universal-links.html#overview">iOS</a> and/or <a href="./android-app-links.html#overview">Android</a> documentation.</li></ul></li><li><p>[Advanced] Use <a href="https://www.charlesproxy.com/" target="_blank" rel="noreferrer">Charles Proxy</a> to verify the domain being sent to Branch in the <code>v1/open</code> request.</p><ul><li><p>Look for <code>universal_link_url</code> and <code>android_app_link_url</code></p></li><li><p>Is the URL present and does it match the original URL you clicked?</p><ul><li><strong>Yes</strong>: Universal Links / App Links is set up properly.</li><li><strong>No</strong>: There&#39;s an issue with your Universal Links or App Links setup. Refer to <a href="./ios-universal-links.html#overview">iOS</a> and/or <a href="./android-app-links.html#overview">Android</a> documentation. Confirm the developer did not exclude specific URLs from being sent to Branch.</li></ul></li></ul></li></ol><h3 id="check-the-referrer-domain" tabindex="-1">Check the referrer domain <a class="header-anchor" href="#check-the-referrer-domain" aria-label="Permalink to &quot;Check the referrer domain&quot;">​</a></h3><p>To confirm that Branch can attribute conversions from SEO or AIO, verify that the SDK is receiving the correct signals.</p><ol><li><p>Find a search result (for SEO testing) or click a link from an AI chat agent (for AIO testing) that matches the URL pattern you registered with Branch.</p></li><li><p>Click on the search result or AI-generated link.</p></li><li><p>Does your app open?</p><ul><li><strong>Yes</strong>: Continue to the next step.</li><li><strong>No</strong>: There&#39;s an issue with your Universal Links or App Links setup. Follow the troubleshooting steps for <a href="#checking-universalapp-links">Checking Universal Links / App Links</a>.</li></ul></li><li><p>[Advanced] Use <a href="https://www.charlesproxy.com/" target="_blank" rel="noreferrer">Charles Proxy</a> to verify the domain and referrer being sent to Branch in the <code>v1/open</code> request.</p><ul><li><p>Look for <code>initial_referrer</code>. Does it match the expected domain (google.com for SEO, or chatgpt.com, gemini.google.com, etc. for AIO)?</p><ul><li><strong>Yes</strong>: Verify in the Branch Dashboard or exports that the session is attributed correctly.</li><li><strong>No</strong>: There&#39;s an issue with your Universal Links or App Links setup. Follow the troubleshooting steps for <a href="#checking-universalapp-links">Checking Universal Links / App Links</a>.</li></ul></li></ul></li></ol><div class="info custom-block"><p class="custom-block-title">Note</p><p>Chrome is not supported on iOS.</p></div>',66)])])}const g=a(i,[["render",n]]);export{u as __pageData,g as default};
